const run = $input.item.json.body.workflow_run;
const repo = $input.item.json.body.repository;

const durationSec = run.updated_at && run.run_started_at
  ? Math.round((new Date(run.updated_at) - new Date(run.run_started_at)) / 1000)
  : 0;

const branch = run.head_branch;
const commit = run.head_sha ? run.head_sha.substring(0, 7) : 'unknown';
const commitMsg = run.head_commit?.message ? run.head_commit.message.split('\n')[0] : 'No commit message';
const actor = run.actor?.login || 'unknown';

return [{
  json: {
    workflow_name: run.name,
    run_number: run.run_number,
    run_url: run.html_url,
    repo_name: repo.full_name,
    repo_url: repo.html_url,
    branch: branch,
    commit: commit,
    commit_url: `${repo.html_url}/commit/${run.head_sha}`,
    commit_message: commitMsg,
    actor: actor,
    duration: durationSec,
    event: run.event,
    message: `🔴 CI FAILED\n\n*${run.name}* #${run.run_number}\n*Repo:* [${repo.full_name}](${repo.html_url})\n*Branch:* \`${branch}\`\n*Commit:* [\`${commit}\`](${repo.html_url}/commit/${run.head_sha}) ${commitMsg}\n*Triggered by:* ${actor} via ${run.event}\n*Duration:* ${durationSec}s\n\n[View Failed Run](${run.html_url})`
  }
}];

